(async () => {
  const REPO = 'Vivian-Faria/orion-escala';
  const FILE = 'index.html';
  const BRANCH = 'main';
  
  console.log('Buscando SHA...');
  const r1 = await fetch(`https://api.github.com/repos/${REPO}/contents/${FILE}`);
  const d1 = await r1.json();
  const sha = d1.sha;
  console.log('SHA:', sha);
  
  const token = prompt('Cole seu GitHub Personal Access Token (precisa de permissao repo):\n(Settings > Developer settings > Personal access tokens > Generate new token)');
  if (!token) { console.log('Cancelado'); return; }
  
  console.log('Fazendo upload (' + Math.round(531784 / 1024) + ' KB)...');
  const r2 = await fetch(`https://api.github.com/repos/${REPO}/contents/${FILE}`, {
    method: 'PUT',
    headers: { 'Authorization': `token ${token}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      message: 'v10: data jornadas, editar ini/fim, fix drag',
      content: ``,
      sha: sha,
      branch: BRANCH
    })
  });
  const d2 = await r2.json();
  if (d2.content) {
    alert('Upload feito! Netlify vai deployar em ~1 minuto.');
  } else {
    console.error('Erro:', JSON.stringify(d2));
    alert('Erro: ' + (d2.message || JSON.stringify(d2)));
  }
})();